import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import 'bootstrap/dist/css/bootstrap.min.css';
import 'bootstrap/dist/js/bootstrap.bundle.min';

// Import des composants
import Header from './components/Header';
import Footer from './components/Footer';

// Import des pages (Assurez-vous que ces fichiers existent dans src/pages/)
import Home from './pages/Home';
import Construction from './pages/Construction';

function App() {
  return (
    <Router>
      <div className="d-flex flex-column min-vh-100">
        <Header />

        <main className="flex-grow-1">
          <Routes>
            <Route path="/" element={<Home />} />

            {/* Routes pour le menu légal demandées par le brief */}
            <Route path="/mentions-legales" element={<Construction />} />
            <Route path="/donnees-personnelles" element={<Construction />} />
            <Route path="/accessibilite" element={<Construction />} />
            <Route path="/cookies" element={<Construction />} />
          </Routes>
        </main>

        <Footer />
      </div>
    </Router>
  );
}

export default App;
